(function(){"use strict";document.addEventListener("click",function(a){var e=a.target.closest('[data-toggle="collapse"]');if(e){var t=e.getAttribute("href");if(!(!t||t.charAt(0)!=="#")){var r=document.querySelector(t);if(r){a.preventDefault();var n=e.getAttribute("data-parent"),l=n?document.querySelector(n):null;l&&l.querySelectorAll(".panel-collapse.in").forEach(function(c){c!==r&&c.classList.remove("in")}),r.classList.toggle("in")}}}})})();
